import java.util.PriorityQueue

fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val directions = listOf(Pair(0L, 1L), Pair(1L, 0L))
    val heap = PriorityQueue<Pair<Long, Triple<Long, Long, Long>>>(compareBy { it.first })
    heap.add(Pair((1L * 1L), Triple(1L, 0L, 0L)))

    val visited = mutableMapOf<Triple<Long, Long, Long>, Long>()
    visited[Triple(1L % 2, 0L, 0L)] = 1L * 1L

    while (heap.isNotEmpty()) {
        val (currentCost, state) = heap.poll()
        val (time, i, j) = state

        if (i == m - 1 && j == n - 1) {
            return currentCost
        }

        if (visited.getOrDefault(Triple(time % 2, i, j), Long.MAX_VALUE) < currentCost) {
            continue
        }

        if (time % 2 == 1L) {
            for ((di, dj) in directions) {
                val ni = i + di
                val nj = j + dj
                if (ni in 0 until m && nj in 0 until n) {
                    val newTime = time + 1
                    val newCost = currentCost + (ni + 1) * (nj + 1)
                    val key = Triple(newTime % 2, ni, nj)
                    if (newCost < visited.getOrDefault(key, Long.MAX_VALUE)) {
                        visited[key] = newCost
                        heap.add(Pair(newCost, Triple(newTime, ni, nj)))
                    }
                }
            }
        } else {
            val newTime = time + 1
            val newCost = currentCost + waitCost[i.toInt()][j.toInt()]
            val key = Triple(newTime % 2, i, j)
            if (newCost < visited.getOrDefault(key, Long.MAX_VALUE)) {
                visited[key] = newCost
                heap.add(Pair(newCost, Triple(newTime, i, j)))
            }
        }
    }

    return -1
}
